def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-12
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 3:
            priority = (ratio ** 5) - (capacity % 5) * 3.3
            for x in range(1, int(capacity) + 3):
                if x % 3 == 0:
                    priority += np.sin(ratio * x) / (x + epsilon)
                elif x % 2 == 0:
                    priority -= np.exp(-ratio * x / (capacity + epsilon))
                else:
                    priority += np.log(x + ratio + epsilon) * np.tanh(ratio / (x + epsilon))
            if capacity % 4 == 0:
                priority *= 1.25
            elif capacity % 2 == 1:
                priority /= 1.17
            else:
                priority += np.sqrt(capacity)
        elif 2 < ratio <= 3:
            priority = (ratio ** 3) * np.sqrt(capacity + 1)
            for m in range(1, int(item) + 2):
                if m % 4 == 0:
                    priority -= (m / (capacity + 1)) ** 1.5
                else:
                    priority += np.cos(m / (item + epsilon))
            if priority < 1:
                priority = 1 - priority
        elif 1 < ratio <= 2:
            priority = (ratio ** 2) * np.log(capacity + 2)
            factor = 1.0
            for n in range(1, 7):
                factor *= (ratio + (n / (capacity + 2))) ** 0.5
                if factor > 10:
                    factor /= 3
                    break
            priority *= factor
            for q in range(1, int(capacity) + 1):
                if q % 5 == 0:
                    priority += np.log(q + 1) / (ratio + epsilon)
                else:
                    priority -= q / (item + epsilon)
            if capacity < item:
                penalty = (item - capacity) ** 2
                priority += penalty / (capacity + epsilon)
        elif 0.5 < ratio <= 1:
            priority = -np.log(1 - ratio + epsilon) * np.sqrt(capacity)
            accumulated = 1.0
            for t in range(1, 10):
                accumulated *= (ratio + t / (capacity + 1))
                if t % 3 == 0 and accumulated > 8:
                    accumulated /= 2
                    break
            priority *= accumulated
            if priority < 0:
                priority = abs(priority) + 2
        elif 0.1 < ratio <= 0.5:
            total = 0
            for j in range(1, int(capacity) + 2):
                val = np.exp(-ratio * j) * np.sin(j)
                if j % 2 == 0:
                    val *= -1
                total += val / (j + epsilon)
            priority = abs(total) + 1.0
        else:
            total = 0
            for z in range(1, int(capacity) * 2):
                val = (ratio ** z) / (z ** 2 + epsilon)
                if z % 2 == 1:
                    val *= np.cos(z)
                else:
                    val *= np.sin(z)
                total += val
                if total > 20:
                    total /= 4
            priority = abs(total) + 0.3
        if capacity < item:
            diff = item - capacity
            penalty = (diff ** 1.5) * 20
            for p in range(1, int(diff) + 3):
                if p % 3 == 0:
                    penalty += np.tanh(p) * 5
                else:
                    penalty -= p * 0.15
            penalty = max(penalty, 0)
            priority += penalty * np.log(1 + diff)
        if np.isnan(priority) or np.isinf(priority):
            priority = 1e6
        priorities[i] = priority
    return priorities
